function:app/src/components/channels/TelegramConfig.tsx:(async () => {
        log('polling telegram link status via core RPC', { key, tokenLength: linkToken.length });
        const startedAt = Date.now();

        try {
          while (Date.now() - startedAt < POLL_TIMEOUT_MS) {
            if (controller.signal.aborted) return;

            try {
              const check = await channelConnectionsApi.telegramLoginCheck(linkToken);
              if (check.linked) {
                log('telegram managed dm linked via core RPC', { key, details: check.details });
                dispatch(
                  upsertChannelConnection({
                    channel: 'telegram',
                    authMode: 'managed_dm',
                    patch: { status: 'connected', lastError: undefined, capabilities: ['dm'] },
                  })
                );
                return;
              }
            } catch {
              // Best-effort polling: keep trying until timeout or cancellation.
            }

            await new Promise<void>(resolve => {
              const timer = window.setTimeout(resolve, POLL_INTERVAL_MS);
              const onAbort = () => {
                window.clearTimeout(timer);
                resolve();
              };
              controller.signal.addEventListener('abort', onAbort, { once: true });
            });
          }

          if (controller.signal.aborted) return;

          dispatch(
            upsertChannelConnection({
              channel: 'telegram',
              authMode: 'managed_dm',
              patch: { status: 'error', lastError: MANAGED_DM_TIMEOUT_MESSAGE },
            })
          );
          setError(MANAGED_DM_TIMEOUT_MESSAGE);
        } catch (pollError) {
          if (controller.signal.aborted) return;

          const msg = pollError instanceof Error ? pollError.message : String(pollError);
          log('managed dm polling failed', { key, error: msg });
          dispatch(
            upsertChannelConnection({
              channel: 'telegram',
              authMode: 'managed_dm',
              patch: { status: 'error', lastError: msg },
            })
          );
          setError(msg);
        } finally {
          if (managedDmPollControllers.current[key] === controller) {
            delete managedDmPollControllers.current[key];
          }
        }
      })

function:app/src/components/channels/YuanbaoConfig.tsx:(async () => {
      try {
        log('connecting yuanbao via %s', spec.mode);
        const result = await channelConnectionsApi.connectChannel('yuanbao', {
          authMode: spec.mode,
          credentials,
        });
        log('connect result: %o', result);

        // Only treat explicit "connected" as success. Any other status
        // (e.g. "pending_auth" if a future auth flow gets added) must
        // surface as an error instead of silently dispatching connected.
        if (result.status !== 'connected') {
          const msg = t('channels.yuanbao.unexpectedStatus').replace(
            '{status}',
            result.status ?? ''
          );
          log('unexpected status: %s', result.status);
          dispatch(
            setChannelConnectionStatus({
              channel: 'yuanbao',
              authMode: spec.mode,
              status: 'error',
              lastError: msg,
            })
          );
          return;
        }

        if (result.restart_required) {
          log('restart required after connect — restarting core process');
          try {
            await restartCoreProcess();
            log('core restart complete, dispatching connected');
            dispatch(
              upsertChannelConnection({
                channel: 'yuanbao',
                authMode: spec.mode,
                patch: {
                  status: 'connected',
                  lastError: undefined,
                  capabilities: ['read', 'write'],
                },
              })
            );
          } catch (restartErr) {
            const msg = restartErr instanceof Error ? restartErr.message : String(restartErr);
            log('core restart failed: %s', msg);
            dispatch(
              setChannelConnectionStatus({
                channel: 'yuanbao',
                authMode: spec.mode,
                status: 'error',
                lastError: t('channels.yuanbao.savedRestartRequired'),
              })
            );
          }
        } else {
          log('no restart required, dispatching connected');
          dispatch(
            upsertChannelConnection({
              channel: 'yuanbao',
              authMode: spec.mode,
              patch: { status: 'connected', lastError: undefined, capabilities: ['read', 'write'] },
            })
          );
        }
      } catch (e) {
        const msg = e instanceof Error ? e.message : String(e);
        log('handleConnect error: %s', msg);
        dispatch(
          setChannelConnectionStatus({
            channel: 'yuanbao',
            authMode: spec.mode,
            status: 'error',
            lastError: msg,
          })
        );
      } finally {
        setBusy(false);
      }
    })

